class Solution:
    def numberOfComponents(self, properties, k):
        n = len(properties)
        sets = [set(p) for p in properties]
        adj = [[] for _ in range(n)]
        for i in range(n):
            for j in range(i + 1, n):
                if len(sets[i] & sets[j]) >= k:
                    adj[i].append(j)
                    adj[j].append(i)
        visited = [False] * n
        components = 0
        for start in range(n):
            if visited[start]:
                continue
            components += 1
            stack = [start]
            visited[start] = True
            while stack:
                u = stack.pop()
                for v in adj[u]:
                    if not visited[v]:
                        visited[v] = True
                        stack.append(v)
        return components

